mapper.update:
UPDATE evd_correction_case
   SET status = 'RESUBMITTED',
       latest_resubmission_snapshot_id = CAST(#{latestSnapshotId} AS uuid)
 WHERE tenant_id = #{tenantId}
   AND correction_case_id = CAST(#{correctionCaseId} AS uuid)
   AND status = #{expectedStatus}

UPDATE evd_correction_case
   SET status = 'CLOSED', closed_by = #{closedBy}, closed_at = #{closedAt}
 WHERE tenant_id = #{tenantId}
   AND correction_case_id = CAST(#{correctionCaseId} AS uuid)
   AND status = #{expectedStatus}

mapper.select:
SELECT result_id::text
  FROM evd_correction_command_result
 WHERE tenant_id = #{tenantId}
   AND operation_type = #{operationType}
   AND idempotency_key = #{idempotencyKey}
